async (params, browser) => {
  // Open issues page
  await browser.open(`https://github.com/${params.repo}/issues`)

  // Wait for issues list
  await browser.waitForSelector('[data-testid=\'issue-row\'], .js-issue-row, .Box-row, [aria-label=\'Issues\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract issues from DOM
  const result = await browser.evaluate(`const issues = []; const rows = document.querySelectorAll('[data-testid="issue-row"], .js-issue-row, .Box-row'); for (let i = 0; i < Math.min(rows.length, 20); i++) { const row = rows[i]; const titleEl = row.querySelector('a[data-hovercard-type="issue"], a.Link--primary, a[id^="issue_"]'); const labels = Array.from(row.querySelectorAll('a.IssueLabel, a[data-name], .lh-default .label')).map(l => l.textContent.trim()); const authorEl = row.querySelector('a[data-hovercard-type="user"], .opened-by a'); const timeEl = row.querySelector('relative-time'); const href = titleEl ? (titleEl.getAttribute('href') || '') : ''; const numberMatch = href.match(/\/(\d+)$/); issues.push({ title: titleEl ? titleEl.textContent.trim() : '', number: numberMatch ? numberMatch[1] : '', labels: labels, author: authorEl ? authorEl.textContent.trim() : '', time: timeEl ? timeEl.getAttribute('datetime') || timeEl.textContent.trim() : '', url: titleEl ? (titleEl.href || ('https://github.com' + href)) : '' }); } const repoPath = window.location.pathname.replace(/\/issues.*/, '').substring(1); return { repo: repoPath, result_count: issues.length, issues: issues }`)

  return result
}
